// Extract action and parameters from webhook
const action = $node["Multi-Purpose Webhook"].json.params.action || 'test';
const query = $node["Multi-Purpose Webhook"].json.query || {};
const body = $node["Multi-Purpose Webhook"].json.body || {};

// Merge query and body parameters
const params = {...query, ...body};

// Define action handlers
const actions = {
  'test': {
    prompt: "What is 2+2? Answer with just the number.",
    json: false,
    max_turns: 1
  },
  'tech-lead': {
    prompt: JSON.stringify({
      role: "Tech LEAD",
      task: "analyze_issues",
      issues: params.issues || [
        {number: 1, title: "Add authentication", priority: "high"},
        {number: 2, title: "Fix typo", priority: "low"},
        {number: 3, title: "Implement API", priority: "medium"}
      ],
      instruction: "Select the highest priority issue to work on. Return JSON with: selected_issue_number, reasoning, estimated_hours"
    }),
    json: true,
    max_turns: 1
  },
  'code-review': {
    prompt: params.code ? 
      `Review this code and provide feedback:\n${params.code}` :
      "Review the following PR changes and provide constructive feedback",
    json: false,
    max_turns: 1
  },
  'decision': {
    prompt: params.question || "Should we proceed with the deployment?",
    context: params.context || {},
    json: true,
    max_turns: 1
  },
  'health': {
    isHealthCheck: true
  }
};

const selectedAction = actions[action] || actions['test'];

if (selectedAction.isHealthCheck) {
  return {
    action: 'health',
    skipClaude: true
  };
}

return {
  action,
  request: selectedAction,
  params,
  timestamp: new Date().toISOString()
};

// Process Claude response
const input = $input.first().json;
const action = $node["Action Router"].json.action;
const params = $node["Action Router"].json.params;

if (input.error) {
  return {
    success: false,
    action,
    error: input.error.message || 'Unknown error',
    timestamp: new Date().toISOString()
  };
}

let result = {
  success: input.success || false,
  action,
  request: {
    prompt_preview: $node["Action Router"].json.request.prompt?.substring(0, 100) + '...',
    params
  },
  response: {
    raw: input.stdout || '',
    error: input.stderr || ''
  },
  execution: {
    command: input.command,
    returncode: input.returncode,
    from: 'container'
  },
  timestamp: new Date().toISOString()
};

// Try to parse JSON responses
if (result.response.raw) {
  const cleanResponse = result.response.raw.trim();
  if (cleanResponse.startsWith('{') || cleanResponse.startsWith('[')) {
    try {
      result.response.parsed = JSON.parse(cleanResponse);

      // For Tech LEAD decisions, extract key information
      if (action === 'tech-lead' && result.response.parsed.selected_issue_number) {
        result.decision = {
          selected_issue: result.response.parsed.selected_issue_number,
          reasoning: result.response.parsed.reasoning,
          estimated_hours: result.response.parsed.estimated_hours
        };
      }
    } catch (e) {
      // Not valid JSON, keep as string
      result.response.text = cleanResponse;
    }
  } else {
    result.response.text = cleanResponse;
  }
}

return result;

// Log to database if configured
const result = $input.first().json;

// Here you would normally save to NocoDB
// For now, just pass through with logging metadata
return {
  ...result,
  logged: true,
  log_timestamp: new Date().toISOString(),
  would_save_to: 'decisions_log table in NocoDB'
};
